// src/services/api.js

const getStorage = (key) => JSON.parse(localStorage.getItem(key) || "[]");
const setStorage = (key, data) => localStorage.setItem(key, JSON.stringify(data));

export const api = {
  // --- AUTH ---
  login: async (email, password) => {
    // Simulamos latencia de red
    await new Promise(resolve => setTimeout(resolve, 800));
    const users = getStorage('usuarios-db');
    const user = users.find(u => u.correo === email && u.password === password);
    if (!user) throw new Error("Credenciales inválidas");
    return user;
  },

  // --- LOCALES & OFERTAS ---
  getLocalesVendedor: (vendedorId) => {
    const locales = getStorage('mis-locales');
    return locales.filter(l => l.vendedorId === vendedorId);
  },

  getOfertasGlobales: () => {
    const locales = getStorage('mis-locales');
    let todas = [];
    locales.forEach(local => {
      const ofertas = getStorage(`ofertas-local-${local.id}`);
      todas = [...todas, ...ofertas.map(o => ({
        ...o,
        localId: local.id,
        nombreLocal: local.nombre,
        lat: local.lat,
        lng: local.lng
      }))];
    });
    return todas;
  },

  // --- PEDIDOS ---
  crearPedido: (pedido) => {
    const pedidos = getStorage('historial-pedidos');
    const nuevo = { ...pedido, id: `PED-${Date.now()}`, estado: 'proceso' };
    setStorage('historial-pedidos', [nuevo, ...pedidos]);
    return nuevo;
  }
};
